// src/pages/MainPage/index.jsx

import React, { useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { Link } from 'react-router-dom';
import { fetchCategories } from '../../store/slices/categoriesSlice';
import { fetchAllProducts } from '../../store/slices/productsSlice'; // Новый Thunk
import CategoryItem from '../../components/CategoryItem';
import ProductCard from '../../components/ProductCard';
import CouponForm from '../../components/CouponForm';
import Button from '../../components/UI/Button';
import s from './MainPage.module.css';

const MainPage = () => {
  const dispatch = useDispatch();

  // Берем только первые 4 категории для отображения на главной (по макету)
  const categories = useSelector(state => state.categories.list).slice(0, 4);
  const categoriesStatus = useSelector(state => state.categories.status);

  // Берем продукты для раздела "Скидки" (фильтруем и берем 4)
  const allProducts = useSelector(state => state.products.list);
  const discountedProducts = allProducts
    .filter(p => p.discont_price !== null && p.discont_price < p.price)
    .slice(0, 4); // Берем первые 4 со скидкой

  // Загружаем данные
  useEffect(() => {
    if (categoriesStatus === 'idle') {
      dispatch(fetchCategories());
    }
    // Загружаем все продукты один раз для поиска скидок
    dispatch(fetchAllProducts());
  }, [dispatch, categoriesStatus]);

  return (
    <div className={s.container}>

      {/* 1. Секция Баннера */}
      <section className={s.banner}>
        <div className={s.bannerContent}>
          <h1>Garden Supply Store</h1>
          <h2>Все, что нужно для вашего сада!</h2>
          <Link to="/products">
            <Button type="primary" className={s.bannerButton}>
              Перейти в каталог
            </Button>
          </Link>
        </div>
      </section>

      {/* 2. Секция Категорий (4 шт.) */}
      <section className={s.section}>
        <div className={s.sectionHeader}>
          <h2>Каталог</h2>
          <Link to="/categories">
            <Button type="secondary">Все категории</Button>
          </Link>
        </div>

        {categoriesStatus === 'loading' ? (
          <p>Загрузка категорий...</p>
        ) : (
          <div className={s.categoriesList}>
            {categories.map(category => (
              <CategoryItem 
                key={category.id} 
                id={category.id} 
                title={category.title} 
                image={category.image} 
              />
            ))}
          </div>
        )}
      </section>

      {/* 3. Секция Скидочного Купона */}
      <section className={s.section}>
        <CouponForm />
      </section>

      {/* 4. Секция Акционных Товаров (Скидки) */}
      <section className={s.section}>
        <div className={s.sectionHeader}>
            <h2>Акции и скидки</h2>
            {/* Ссылка на /products, если хочешь показать все товары */}
            <Link to="/products">
                <Button type="secondary">Все товары</Button>
            </Link>
        </div>
        <div className={s.productsList}>
          {discountedProducts.map(product => (
            <ProductCard 
              key={product.id}
              id={product.id}
              title={product.title}
              price={product.price}
              discont_price={product.discont_price}
              image={product.image}
            />
          ))}
        </div>
      </section>

    </div>
  );
};

export default MainPage;
